const Web3 = require('web3');
require('dotenv').config();

// Connect to the network (default is 'localhost' at port 8545)
let web3 = new Web3(process.env.PROVIDER_URL);

async function sendTransaction() {
    // Import private key for transaction signing (replace with your own key)
    const account = web3.eth.accounts.privateKeyToAccount('0x' + process.env.PRIVATE_KEY); 

    // Add the account to the Web3 instance
    web3.eth.accounts.wallet.add(account);
    
    // Set default sender
    web3.eth.defaultAccount = account.address;
    
    let txCount = await web3.eth.getTransactionCount('0x' + process.env.FROM_ADDRESS); 
     
    return web3.eth.sendTransaction({
        to: '0x' + process.env.TO_ADDRESS,
        gasPrice: await web3.eth.getGasPrice(),
        gas: 21000,
        value: web3.utils.toWei('1', 'ether'),   // sending 1 ETH
        nonce: txCount 
    });
}

async function callContractFunction(contractAddress, contractABI, methodName, ...args) {
    const contract = new web3.eth.Contract(contractABI, contractAddress);
    
    return contract.methods[methodName](...args).call();
}

sendTransaction()
  .then(receipt => console.log('Transaction receipt: ', receipt))
  .catch(err => console.error('Failed to send transaction: ', err));
  
callContractFunction('0xYourSmartContractAddress', 'YourContractABI', 'yourMethodName')
  .then(result => console.log('Call result: ', result))
  .catch(err => console.error('Failed to call contract function: ', err));